/**
 * Generates dist/serialization-model.json — the data the canonical serializer
 * needs to make TS emit byte-identical to the .NET multitool.
 *
 * Two single sources, merged at build time (never checked in, regenerated on
 * every build so neither can drift):
 *
 *  - Key ORDER comes from the .NET SDK's autogenerated object model
 *    (src/Sarif/Autogenerated/*.cs). The multitool serializes through its
 *    typed model, so the on-disk order is the model's DataMember order: C#
 *    property *declaration* order, overridden by an explicit `Order = N` when
 *    jschema emitted one (e.g. ReportingDescriptor, where the desired
 *    serialization order differs from the schema's property order). This is the
 *    exact authority that drives Newtonsoft.
 *
 *  - The prop -> child-type GRAPH (needed to know which type each node in the
 *    SARIF tree is, so the right order applies) comes from the published SARIF
 *    schema (src/Sarif/Schemata/sarif-2.1.0-rtm.6.json) via its $ref edges.
 *    Property-bag-typed slots are tagged so the serializer preserves their
 *    insertion order rather than reordering them.
 *
 * Output shape: { "<definition>": { order: string[], children: { <prop>: "<childDef>" | "@propertyBag" } } }
 * plus a synthetic "sarifLog" root entry.
 */

import { readFileSync, writeFileSync, readdirSync, mkdirSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = join(here, '..', '..', '..');
const autogenDir = join(repoRoot, 'src', 'Sarif', 'Autogenerated');
const schemaPath = join(repoRoot, 'src', 'Sarif', 'Schemata', 'sarif-2.1.0-rtm.6.json');
const outDir = join(here, '..', 'dist');
const outFile = join(outDir, 'serialization-model.json');

const PROPERTY_BAG = '@propertyBag';
const DATAMEMBER_RE = /\[DataMember\(Name = "([^"]+)"([^\]]*)\)\]/g;
const ORDER_RE = /Order = (\d+)/;

function camelCase(name) {
  return name.length === 0 ? name : name[0].toLowerCase() + name.slice(1);
}

// --- ORDER: parse the autogenerated C# model -------------------------------

function orderedPropsFor(source) {
  const props = [];
  let m;
  let idx = 0;
  DATAMEMBER_RE.lastIndex = 0;
  while ((m = DATAMEMBER_RE.exec(source)) !== null) {
    const orderMatch = ORDER_RE.exec(m[2]);
    props.push({ name: m[1], order: orderMatch ? Number(orderMatch[1]) : null, idx: idx++ });
  }
  if (props.length === 0) return null;

  if (props.some((p) => p.order !== null)) {
    // Stable sort by explicit Order; ties (jschema occasionally repeats a
    // value) and unannotated members fall back to declaration order.
    props.sort((a, b) => {
      const ao = a.order ?? a.idx;
      const bo = b.order ?? b.idx;
      return ao === bo ? a.idx - b.idx : ao - bo;
    });
  }
  return props.map((p) => p.name);
}

const orderByDef = {};
for (const file of readdirSync(autogenDir)) {
  if (!file.endsWith('.cs')) continue;
  const source = readFileSync(join(autogenDir, file), 'utf8');
  const classMatch = /public partial class (\w+)/.exec(source);
  if (!classMatch) continue;
  const order = orderedPropsFor(source);
  if (order) orderByDef[camelCase(classMatch[1])] = order;
}

// --- CHILD TYPES: walk the schema $ref graph -------------------------------

const schema = JSON.parse(readFileSync(schemaPath, 'utf8'));

function refName(node) {
  if (node && typeof node.$ref === 'string') {
    const m = /#\/definitions\/(.+)$/.exec(node.$ref);
    return m ? m[1] : null;
  }
  return null;
}

/** Returns the child definition (or @propertyBag) a property slot resolves to, else null. */
function childTypeOf(propSchema) {
  if (!propSchema) return null;
  const direct = refName(propSchema);
  if (direct === 'propertyBag') return PROPERTY_BAG;
  if (direct) return direct;
  if (propSchema.type === 'array' && propSchema.items) {
    const item = refName(propSchema.items);
    if (item === 'propertyBag') return PROPERTY_BAG;
    if (item) return item;
  }
  return null;
}

function childrenOf(propertiesNode) {
  const children = {};
  if (!propertiesNode) return children;
  for (const [prop, propSchema] of Object.entries(propertiesNode)) {
    const child = childTypeOf(propSchema);
    if (child) children[prop] = child;
  }
  return children;
}

const model = {};
for (const [defName, def] of Object.entries(schema.definitions ?? {})) {
  const order = orderByDef[defName];
  if (!order) continue; // no typed model order (enums etc.) -> nothing to reorder
  model[defName] = { order, children: childrenOf(def.properties) };
}

// Synthetic root: SarifLog isn't a schema definition; pull its children from
// the schema root's own properties, its order from SarifLog.cs.
model.sarifLog = {
  order: orderByDef.sarifLog ?? Object.keys(schema.properties ?? {}),
  children: childrenOf(schema.properties),
};

mkdirSync(outDir, { recursive: true });
writeFileSync(outFile, JSON.stringify(model, null, 2) + '\n', 'utf8');
console.log(`serialization-model.json: ${Object.keys(model).length} types -> ${outFile}`);
